     1→/*
     2→ * Todo List Application -- Main Stylesheet
     3→ *
     4→ * CSS Architecture: Cascade Layers
     5→ * ---------------------------------
     6→ * Layers control specificity order regardless of source order.
     7→ * Earlier layers have lower priority; later layers win ties.
     8→ *
     9→ * @layer reset     -- Normalize browser defaults
    10→ * @layer tokens    -- Design tokens (CSS custom properties on :root)
    11→ * @layer base      -- Element-level styles (body, headings, links, forms)
    12→ * @layer layout    -- Page-level layout (CSS Grid, containers)
    13→ * @layer components -- Component-specific styles (added per feature)
    14→ * @layer utilities -- Helper classes (visually-hidden, etc.)
    15→ */
    16→
    17→@layer reset, tokens, base, layout, components, utilities;
    18→
    19→/* ==========================================================================
    20→   RESET LAYER
    21→   Modern CSS reset. Removes browser inconsistencies while preserving
    22→   useful defaults. Based on Andy Bell's modern reset.
    23→   ========================================================================== */
    24→
    25→@layer reset {
    26→  *,
    27→  *::before,
    28→  *::after {
    29→    box-sizing: border-box;
    30→  }
    31→
    32→  * {
    33→    margin: 0;
    34→    padding: 0;
    35→  }
    36→
    37→  html {
    38→    -moz-text-size-adjust: none;
    39→    -webkit-text-size-adjust: none;
    40→    text-size-adjust: none;
    41→  }
    42→
    43→  body {
    44→    min-block-size: 100vh;
    45→    line-height: 1.5;
    46→    -webkit-font-smoothing: antialiased;
    47→  }
    48→
    49→  img,
    50→  picture,
    51→  video,
    52→  canvas,
    53→  svg {
    54→    display: block;
    55→    max-inline-size: 100%;
    56→  }
    57→
    58→  input,
    59→  button,
    60→  textarea,
    61→  select {
    62→    font: inherit;
    63→    color: inherit;
    64→  }
    65→
    66→  p,
    67→  h1,
    68→  h2,
    69→  h3,
    70→  h4,
    71→  h5,
    72→  h6 {
    73→    overflow-wrap: break-word;
    74→  }
    75→
    76→  h1,
    77→  h2,
    78→  h3,
    79→  h4,
    80→  h5,
    81→  h6 {
    82→    text-wrap: balance;
    83→  }
    84→
    85→  a {
    86→    color: inherit;
    87→    text-decoration-skip-ink: auto;
    88→  }
    89→
    90→  ul[role="list"],
    91→  ol[role="list"] {
    92→    list-style: none;
    93→  }
    94→
    95→  /* Remove default button styles */
    96→  button {
    97→    cursor: pointer;
    98→    background: none;
    99→    border: none;
   100→  }
   101→
   102→  /* Remove animations and transitions for users who prefer reduced motion */
   103→  @media (prefers-reduced-motion: reduce) {
   104→    *,
   105→    *::before,
   106→    *::after {
   107→      animation-duration: 0.01ms !important;
   108→      animation-iteration-count: 1 !important;
   109→      transition-duration: 0.01ms !important;
   110→      scroll-behavior: auto !important;
   111→    }
   112→  }
   113→}
   114→
   115→/* ==========================================================================
   116→   TOKENS LAYER
   117→   Design tokens as CSS custom properties on :root.
   118→
   119→   Token system:
   120→   - Spacing:    4px base unit, named --space-xs through --space-3xl
   121→   - Colors:     oklch color space for perceptual uniformity
   122→   - Typography: System font stack, fluid type scale with clamp()
   123→   - Shadows:    Three levels (sm, md, lg)
   124→   - Radii:      Three sizes (sm, md, lg)
   125→   - Transitions: Duration values for consistent animation timing
   126→
   127→   All component styles reference tokens -- no hardcoded values.
   128→   Token changes go through the mob with Steve Schoger's approval.
   129→   ========================================================================== */
   130→
   131→@layer tokens {
   132→  :root {
   133→    /* ---- Spacing Scale ----
   134→     * 4px base unit. Numbered primitives map to multiples of 4px.
   135→     * Semantic aliases below provide meaningful names for common uses.
   136→     * Scale: 4, 8, 12, 16, 24, 32, 48, 64, 96
   137→     */
   138→    --space-1:  0.25rem;  /* 4px */
   139→    --space-2:  0.5rem;   /* 8px */
   140→    --space-3:  0.75rem;  /* 12px */
   141→    --space-4:  1rem;     /* 16px */
   142→    --space-6:  1.5rem;   /* 24px */
   143→    --space-8:  2rem;     /* 32px */
   144→    --space-12: 3rem;     /* 48px */
   145→    --space-16: 4rem;     /* 64px */
   146→    --space-24: 6rem;     /* 96px */
   147→
   148→    /* Semantic spacing aliases */
   149→    --space-xs:  var(--space-1);   /* 4px */
   150→    --space-sm:  var(--space-2);   /* 8px */
   151→    --space-md:  var(--space-4);   /* 16px */
   152→    --space-lg:  var(--space-6);   /* 24px */
   153→    --space-xl:  var(--space-8);   /* 32px */
   154→    --space-2xl: var(--space-12);  /* 48px */
   155→    --space-3xl: var(--space-16);  /* 64px */
   156→
   157→    /* ---- Color Palette ----
   158→     * oklch color space for perceptual uniformity.
   159→     * Most UI is grayscale; color is for emphasis and interaction.
   160→     * "The grays do the heavy lifting, primary blue is supporting cast."
   161→     *
   162→     * oklch(Lightness Chroma Hue)
   163→     * - Lightness: 0 (black) to 1 (white)
   164→     * - Chroma: 0 (gray) to ~0.4 (most saturated)
   165→     * - Hue: 0-360 degrees
   166→     */
   167→
   168→    /* Neutral grays -- zero chroma for true neutrals
   169→     *
   170→     * Contrast ratios vs white (#fff):
   171→     *   gray-50 to gray-300: decorative/border use only, NOT for text
   172→     *   gray-400 (~0.71): ~3:1  -- large text/UI components minimum
   173→     *   gray-500 (~0.55): ~4.6:1 -- normal text AA (borderline)
   174→     *   gray-600 (~0.45): ~7:1  -- normal text AA, comfortable
   175→     *   gray-700+:         ~10:1+ -- high contrast
   176→     *
   177→     * For text on light backgrounds, use gray-500 or darker for AA. */
   178→    --color-gray-50:  oklch(0.985 0 0); /* near-white backgrounds */
   179→    --color-gray-100: oklch(0.97 0 0);  /* subtle backgrounds, hover states */
   180→    --color-gray-200: oklch(0.925 0 0); /* borders, dividers */
   181→    --color-gray-300: oklch(0.87 0 0);  /* disabled text, emphasized borders */
   182→    --color-gray-400: oklch(0.71 0 0);  /* muted text (large only), icons */
   183→    --color-gray-500: oklch(0.55 0 0);  /* secondary text */
   184→    --color-gray-600: oklch(0.45 0 0);  /* body text */
   185→    --color-gray-700: oklch(0.37 0 0);  /* strong text */
   186→    --color-gray-800: oklch(0.27 0 0);  /* headings */
   187→    --color-gray-900: oklch(0.18 0 0);  /* near-black, high emphasis */
   188→
   189→    /* Primary -- blue for interactive elements.
   190→     * One blue. Used for links, buttons, focus rings. That's it.
   191→     * Hue 240, moderate chroma for a professional look. */
   192→    --color-primary-light: oklch(0.75 0.1 240);  /* hover states, light badges */
   193→    --color-primary:       oklch(0.55 0.18 240);  /* buttons, links, active states */
   194→    --color-primary-dark:  oklch(0.42 0.18 240);  /* pressed states, dark accents */
   195→
   196→    /* Semantic colors
   197→     * IMPORTANT: Color must never be the sole indicator of state.
   198→     * Every use of danger/success/warning must be paired with a
   199→     * secondary visual cue: icon, text label, strikethrough, border
   200→     * style change, etc. This is a WCAG requirement and team agreement. */
   201→    --color-danger:        oklch(0.55 0.2 25);   /* destructive actions, errors */
   202→    --color-danger-light:  oklch(0.92 0.04 25);  /* danger backgrounds */
   203→    --color-success:       oklch(0.6 0.17 145);  /* completed states */
   204→    --color-success-light: oklch(0.92 0.04 145); /* success backgrounds */
   205→    --color-warning:       oklch(0.75 0.15 75);  /* warnings */
   206→    --color-warning-light: oklch(0.93 0.04 75);  /* warning backgrounds */
   207→
   208→    /* Foreground / background semantic tokens */
   209→    --color-bg:            var(--color-gray-50);   /* page background */
   210→    --color-bg-raised:     white;                  /* cards, raised surfaces */
   211→    --color-fg:            var(--color-gray-800);  /* primary text */
   212→    --color-fg-muted:      var(--color-gray-500);  /* secondary text (~4.6:1 vs white) */
   213→    --color-fg-subtle:     var(--color-gray-400);  /* placeholders, hint text (3:1 -- NOT for body text) */
   214→    --color-border:        var(--color-gray-200);  /* default borders */
   215→    --color-border-strong: var(--color-gray-300);  /* emphasized borders, input focus */
   216→
   217→    /* ---- Typography ----
   218→     * System font stack -- no web font downloads, instant rendering.
   219→     * Fluid type scale using clamp() for smooth scaling between
   220→     * viewport sizes. Min at ~320px, max at ~1200px.
   221→     */
   222→    --font-sans: system-ui, -apple-system, "Segoe UI", Roboto,
   223→      "Helvetica Neue", Arial, sans-serif;
   224→
   225→    --font-mono: ui-monospace, "Cascadia Code", "Source Code Pro",
   226→      Menlo, Consolas, "DejaVu Sans Mono", monospace;
   227→
   228→    /* Fluid type scale
   229→     * clamp(min, preferred, max)
   230→     * Preferred uses viewport units for smooth scaling */
   231→    --font-size-xs:   clamp(0.6875rem, 0.65rem + 0.1vw, 0.75rem);     /* ~11-12px, fine print */
   232→    --font-size-sm:   clamp(0.8125rem, 0.78rem + 0.1vw, 0.875rem);    /* ~13-14px, captions */
   233→    --font-size-base: clamp(0.9375rem, 0.9rem + 0.12vw, 1rem);        /* ~15-16px, body text */
   234→    --font-size-lg:   clamp(1.0625rem, 1rem + 0.15vw, 1.125rem);      /* ~17-18px, subheadings */
   235→    --font-size-xl:   clamp(1.1875rem, 1.1rem + 0.2vw, 1.3125rem);    /* ~19-21px, section headings */
   236→    --font-size-2xl:  clamp(1.4375rem, 1.3rem + 0.3vw, 1.625rem);     /* ~23-26px, page headings */
   237→    --font-size-3xl:  clamp(1.75rem, 1.6rem + 0.4vw, 2.125rem);       /* ~28-34px, hero/display */
   238→
   239→    /* Line heights */
   240→    --leading-tight:   1.25;   /* headings */
   241→    --leading-snug:    1.375;  /* subheadings, large text */
   242→    --leading-normal:  1.5;    /* body text */
   243→    --leading-relaxed: 1.625;  /* small text that needs more air */
   244→
   245→    /* Font weights */
   246→    --font-normal:    400;
   247→    --font-medium:    500;
   248→    --font-semibold:  600;
   249→    --font-bold:      700;
   250→
   251→    /* ---- Shadows ----
   252→     * Three levels. Shadows use oklch for consistency with the color system.
   253→     * Never combine shadows and borders on the same element (per team agreement).
   254→     */
   255→    --shadow-sm:  0 1px 2px oklch(0.18 0 0 / 0.05);
   256→    --shadow-md:  0 4px 6px -1px oklch(0.18 0 0 / 0.07),
   257→                  0 2px 4px -2px oklch(0.18 0 0 / 0.05);
   258→    --shadow-lg:  0 10px 15px -3px oklch(0.18 0 0 / 0.08),
   259→                  0 4px 6px -4px oklch(0.18 0 0 / 0.04);
   260→
   261→    /* ---- Border Radius ---- */
   262→    --radius-sm:   0.25rem;  /* 4px -- badges, tags */
   263→    --radius-md:   0.5rem;   /* 8px -- buttons, inputs, cards */
   264→    --radius-lg:   0.75rem;  /* 12px -- larger containers, modals */
   265→    --radius-full: 9999px;   /* pills, avatars */
   266→
   267→    /* ---- Transition Durations ----
   268→     * All transitions MUST be wrapped in
   269→     * @media (prefers-reduced-motion: no-preference).
   270→     * Easing: ease (not ease-in-out).
   271→     */
   272→    --transition-fast:   100ms;  /* micro-interactions: hover, focus */
   273→    --transition-normal: 200ms;  /* standard: expand, slide */
   274→    --transition-slow:   300ms;  /* larger: modal, page */
   275→
   276→    /* ---- Focus Ring ----
   277→     * Reusable focus ring properties for consistent :focus-visible styles.
   278→     * 3:1+ contrast against background (blue on white/light gray).
   279→     */
   280→    --focus-ring-color:  var(--color-primary);
   281→    --focus-ring-offset: 2px;
   282→    --focus-ring-width:  2px;
   283→  }
   284→}
   285→
   286→/* ==========================================================================
   287→   BASE LAYER
   288→   Element-level styles applied directly to HTML elements.
   289→   No classes -- this establishes the typographic and interactive baseline.
   290→   ========================================================================== */
   291→
   292→@layer base {
   293→  body {
   294→    font-family: var(--font-sans);
   295→    font-size: var(--font-size-base);
   296→    font-weight: var(--font-normal);
   297→    line-height: var(--leading-normal);
   298→    color: var(--color-fg);
   299→    background-color: var(--color-bg);
   300→  }
   301→
   302→  /* Headings -- tighter line-height, bolder weight, type scale */
   303→  h1 {
   304→    font-size: var(--font-size-3xl);
   305→    font-weight: var(--font-bold);
   306→    line-height: var(--leading-tight);
   307→  }
   308→
   309→  h2 {
   310→    font-size: var(--font-size-2xl);
   311→    font-weight: var(--font-bold);
   312→    line-height: var(--leading-tight);
   313→  }
   314→
   315→  h3 {
   316→    font-size: var(--font-size-xl);
   317→    font-weight: var(--font-semibold);
   318→    line-height: var(--leading-snug);
   319→  }
   320→
   321→  h4 {
   322→    font-size: var(--font-size-lg);
   323→    font-weight: var(--font-semibold);
   324→    line-height: var(--leading-snug);
   325→  }
   326→
   327→  h5,
   328→  h6 {
   329→    font-size: var(--font-size-base);
   330→    font-weight: var(--font-medium);
   331→    line-height: var(--leading-snug);
   332→  }
   333→
   334→  /* Links */
   335→  a {
   336→    color: var(--color-primary);
   337→    text-decoration: underline;
   338→    text-underline-offset: 0.15em;
   339→
   340→    &:hover {
   341→      color: var(--color-primary-dark);
   342→    }
   343→  }
   344→
   345→  /* Focus-visible styles for all interactive elements.
   346→   * Uses outline for keyboard focus, visible only on keyboard navigation.
   347→   * Double-ring technique: white inner ring (box-shadow) + colored outer ring
   348→   * (outline) ensures visibility on both light and dark backgrounds.
   349→   * 3:1+ contrast ratio maintained in all contexts. */
   350→  :focus-visible {
   351→    outline: var(--focus-ring-width) solid var(--focus-ring-color);
   352→    outline-offset: var(--focus-ring-offset);
   353→    box-shadow: 0 0 0 var(--focus-ring-offset) white;
   354→  }
   355→
   356→  /* Buttons -- base styles, ready for component overrides */
   357→  button,
   358→  [type="button"],
   359→  [type="submit"],
   360→  [type="reset"] {
   361→    display: inline-flex;
   362→    align-items: center;
   363→    justify-content: center;
   364→    gap: var(--space-sm);
   365→    padding-block: var(--space-sm);
   366→    padding-inline: var(--space-md);
   367→    font-size: var(--font-size-base);
   368→    font-weight: var(--font-medium);
   369→    line-height: var(--leading-tight);
   370→    border-radius: var(--radius-md);
   371→    background-color: var(--color-primary);
   372→    color: white;
   373→
   374→    &:hover {
   375→      background-color: var(--color-primary-dark);
   376→    }
   377→  }
   378→
   379→  @media (prefers-reduced-motion: no-preference) {
   380→    button,
   381→    [type="button"],
   382→    [type="submit"],
   383→    [type="reset"] {
   384→      transition: background-color var(--transition-fast) ease;
   385→    }
   386→  }
   387→
   388→  /* Form inputs */
   389→  input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   390→  textarea,
   391→  select {
   392→    display: block;
   393→    inline-size: 100%;
   394→    padding-block: var(--space-sm);
   395→    padding-inline: var(--space-3);
   396→    font-size: var(--font-size-base);
   397→    line-height: var(--leading-normal);
   398→    color: var(--color-fg);
   399→    background-color: var(--color-bg-raised);
   400→    border: 1px solid var(--color-border);
   401→    border-radius: var(--radius-md);
   402→
   403→    &::placeholder {
   404→      color: var(--color-fg-subtle);
   405→    }
   406→  }
   407→
   408→  /* Labels */
   409→  label {
   410→    display: block;
   411→    font-size: var(--font-size-sm);
   412→    font-weight: var(--font-medium);
   413→    color: var(--color-fg);
   414→  }
   415→
   416→  /* Fieldset */
   417→  fieldset {
   418→    border: none;
   419→  }
   420→
   421→  /* Code */
   422→  code,
   423→  pre {
   424→    font-family: var(--font-mono);
   425→    font-size: var(--font-size-sm);
   426→  }
   427→
   428→  /* Windows High Contrast Mode support.
   429→   * In forced-colors mode, the browser overrides most colors.
   430→   * We ensure borders, outlines, and structural indicators remain
   431→   * visible since they become the primary way to distinguish elements. */
   432→  @media (forced-colors: active) {
   433→    button,
   434→    [type="button"],
   435→    [type="submit"],
   436→    [type="reset"] {
   437→      border: 1px solid ButtonText;
   438→    }
   439→
   440→    input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   441→    textarea,
   442→    select {
   443→      border: 1px solid ButtonText;
   444→    }
   445→
   446→    :focus-visible {
   447→      outline: 2px solid Highlight;
   448→      outline-offset: 2px;
   449→    }
   450→  }
   451→}
   452→
   453→/* ==========================================================================
   454→   LAYOUT LAYER
   455→   Page-level layout using CSS Grid. Mobile-first, desktop breakpoint ~1024px.
   456→   Uses logical properties for RTL support.
   457→   ========================================================================== */
   458→
   459→@layer layout {
   460→  /* Page layout: header / main / footer with sticky footer */
   461→  .page-layout {
   462→    display: grid;
   463→    grid-template-rows: auto 1fr auto;
   464→    min-block-size: 100vh;
   465→  }
   466→
   467→  /* Constrained content container */
   468→  .container {
   469→    inline-size: 100%;
   470→    max-inline-size: 40rem; /* ~640px -- a todo list is narrow */
   471→    margin-inline: auto;
   472→    padding-inline: var(--space-md);
   473→  }
   474→
   475→  /* Wider container variant for pages that need more space */
   476→  .container--wide {
   477→    max-inline-size: 64rem; /* ~1024px */
   478→  }
   479→
   480→  /* Responsive adjustments */
   481→  @media (min-width: 1024px) {
   482→    .container {
   483→      padding-inline: var(--space-lg);
   484→    }
   485→  }
   486→
   487→  /* Container query setup -- components can respond to their container */
   488→  .component-container {
   489→    container-type: inline-size;
   490→  }
   491→}
   492→
   493→/* ==========================================================================
   494→   COMPONENTS LAYER
   495→   Component-specific styles are added here as features are built.
   496→   Each component should be self-contained and reference only design tokens.
   497→   ========================================================================== */
   498→
   499→@layer components {
   500→  /* Components will be added here as features are developed.
   501→   * Each feature's CSS goes in this layer.
   502→   * Example (future):
   503→   *   .todo-item { ... }
   504→   *   .auth-form { ... }
   505→   */
   506→}
   507→
   508→/* ==========================================================================
   509→   UTILITIES LAYER
   510→   Helper classes. These have the highest layer priority.
   511→   ========================================================================== */
   512→
   513→@layer utilities {
   514→  /* Visually hidden -- accessible to screen readers but not visible.
   515→   * Uses the clip technique for reliable hiding.
   516→   * white-space: nowrap prevents content from being announced as
   517→   * multiple separate items by some screen readers. */
   518→  .visually-hidden,
   519→  .sr-only {
   520→    position: absolute;
   521→    inline-size: 1px;
   522→    block-size: 1px;
   523→    padding: 0;
   524→    margin: -1px;
   525→    overflow: hidden;
   526→    clip: rect(0 0 0 0);
   527→    clip-path: inset(50%);
   528→    white-space: nowrap;
   529→    border: 0;
   530→  }
   531→}
   532→

